import{_ as t,H as r,f as e,i as o}from"./chunks/framework.Cvt1eIE0.js";const g=JSON.parse('{"title":"数据分析","description":"","frontmatter":{},"headers":[],"relativePath":"store-locator/guide/analytics.md","filePath":"store-locator/guide/analytics.md"}'),n={name:"store-locator/guide/analytics.md"};function i(l,a,s,h,d,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="数据分析" tabindex="-1">数据分析 <a class="header-anchor" href="#数据分析" aria-label="Permalink to &quot;数据分析&quot;">​</a></h1><p>Jika Store Locator 提供了强大的数据分析功能，帮助您了解客户如何与您的门店定位器互动。您可以追踪搜索趋势、热门门店以及客户的交互行为。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>在应用导航栏中点击 <strong>Analytics (分析)</strong> 即可进入数据分析仪表盘。通过仪表盘，您可以直观地看到定位器的运行表现。</p><h2 id="核心指标" tabindex="-1">核心指标 <a class="header-anchor" href="#核心指标" aria-label="Permalink to &quot;核心指标&quot;">​</a></h2><ul><li><strong>浏览量 (Views)</strong>：定位器页面被访问或悬浮挂件被打开的总次数。</li><li><strong>搜索次数 (Searches)</strong>：客户在定位器中使用搜索框进行查询的次数。</li><li><strong>门店交互 (Store Actions)</strong>：客户点击“获取路线”或“联系我们”的总次数。</li><li><strong>交互率 (Action Rate)</strong>：衡量客户参与度的关键指标，即平均每次浏览产生的交互比例。</li></ul><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><h3 id="_1-活动趋势图" tabindex="-1">1. 活动趋势图 <a class="header-anchor" href="#_1-活动趋势图" aria-label="Permalink to &quot;1. 活动趋势图&quot;">​</a></h3><p>可视化展示所选时间范围内定位器的使用频率，帮助您识别流量高峰期。</p><h3 id="_2-来源分析" tabindex="-1">2. 来源分析 <a class="header-anchor" href="#_2-来源分析" aria-label="Permalink to &quot;2. 来源分析&quot;">​</a></h3><p>查看客户是通过<strong>独立定位器页面</strong>还是通过<strong>悬浮挂件</strong>进入的，了解不同入口的使用偏好。</p><h3 id="_3-热门搜索词" tabindex="-1">3. 热门搜索词 <a class="header-anchor" href="#_3-热门搜索词" aria-label="Permalink to &quot;3. 热门搜索词&quot;">​</a></h3><p>显示客户最常搜索的关键词。这可以帮助您了解客户对哪些区域的门店最感兴趣，为您的业务扩张提供参考。</p><h3 id="_4-热门门店榜单" tabindex="-1">4. 热门门店榜单 <a class="header-anchor" href="#_4-热门门店榜单" aria-label="Permalink to &quot;4. 热门门店榜单&quot;">​</a></h3><p>基于导航点击和联系点击量，自动排列出最受客户关注的门店。</p><h3 id="_5-交互漏斗" tabindex="-1">5. 交互漏斗 <a class="header-anchor" href="#_5-交互漏斗" aria-label="Permalink to &quot;5. 交互漏斗&quot;">​</a></h3><p>展示从“浏览”到“搜索”再到“产生交互”的转化过程，帮助您评估定位器的引导效果。</p><h2 id="日期筛选与导出" tabindex="-1">日期筛选与导出 <a class="header-anchor" href="#日期筛选与导出" aria-label="Permalink to &quot;日期筛选与导出&quot;">​</a></h2><ul><li><strong>日期范围</strong>：您可以选择最近 7 天、30 天、60 天，或使用自定义日期选择器查看特定时间段的数据。</li><li><strong>导出 CSV</strong>：点击页面右上角的 <strong>Export CSV</strong> 按钮，可以将当前的详细活动记录下载到本地进行二次分析。</li></ul><h2 id="数据保留政策" tabindex="-1">数据保留政策 <a class="header-anchor" href="#数据保留政策" aria-label="Permalink to &quot;数据保留政策&quot;">​</a></h2><p>为了保证系统性能并符合数据隐私最佳实践，应用仅保留最近 <strong>60 天</strong> 的分析数据。超过 60 天的数据将被自动清理。</p><h2 id="方案限制" tabindex="-1">方案限制 <a class="header-anchor" href="#方案限制" aria-label="Permalink to &quot;方案限制&quot;">​</a></h2><p>高级数据分析功能（包括详细报表和 CSV 导出）仅对 <strong>Pro</strong> 和 <strong>Enterprise</strong> 方案的用户开放。如果您当前使用的是基础方案，仪表盘将显示预览模式。您可以前往 <strong>Pricing (定价)</strong> 页面随时升级您的方案。</p>',23)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
